(()=>{
  const mount=document.querySelector('[data-home-impact]');
  if(!mount) return;

  const esc=(value)=>String(value ?? '')
    .replaceAll('&','&amp;')
    .replaceAll('<','&lt;')
    .replaceAll('>','&gt;')
    .replaceAll('"','&quot;')
    .replaceAll("'",'&#39;');

  const preferredPrograms=['BUMI','SIDIK'];

  function pickPrograms(items){
    const list=Array.isArray(items)?items:[];
    const picked=[];

    preferredPrograms.forEach((keyword)=>{
      const match=list.find((item)=>String(item?.title||'').toUpperCase().includes(keyword));
      if(match && !picked.includes(match)) picked.push(match);
    });

    if(picked.length<2){
      list.forEach((item)=>{
        if(picked.length<2 && !picked.includes(item)) picked.push(item);
      });
    }

    return picked.slice(0,2);
  }

  function render(items){
    const visible=pickPrograms(items);
    const duo=visible.length===2;
    mount.classList.toggle('home-impact__grid--duo', duo);

    if(!visible.length){
      mount.innerHTML='<p class="home-impact__empty">Program unggulan akan ditampilkan di sini.</p>';
      return;
    }

    mount.innerHTML=visible.map((item,index)=>{
      const title=esc(item.title||'Program');
      const tag=esc(item.tag||'IKSASS');
      const desc=esc(item.desc||'');
      const href=esc(item.href||'#');
      const featured=index===0;
      const support=duo && index===1;
      const points=Array.isArray(item.points)?item.points.slice(0,3):[];
      const pointHtml=points.length ? `<ul class="impact-points">${points.map(point=>`<li>${esc(point)}</li>`).join('')}</ul>` : '';
      const logoSrc=item.logo ? esc(item.logo) : '';
      const logoHtml=logoSrc ? `
        <div class="impact-logo-wrap">
          <img class="impact-logo" src="${logoSrc}" alt="Logo ${title}" loading="lazy">
        </div>` : '';
      return `
        <a class="card impact-card${featured?' is-featured':''}${support?' impact-card--support':''}${logoSrc?' impact-card--with-logo':''}" href="${href}">
          <div class="impact-card__head">
            <span class="impact-tag">${tag}</span>
            <svg class="impact-arrow" aria-hidden="true" viewBox="0 0 24 24" width="18" height="18" focusable="false">
              <path d="M9 18l6-6-6-6" fill="none" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2"/>
            </svg>
          </div>${logoHtml}
          <h3 class="impact-title">${title}</h3>
          <p class="impact-desc">${desc}</p>
          ${pointHtml}
          <span class="impact-cta">Pelajari →</span>
        </a>`;
    }).join('');
  }

  async function init(){
    try{
      const res=await fetch(new URL('assets/data/impact.json',document.baseURI).toString(),{cache:'no-store'});
      if(!res.ok) throw new Error(`impact.json: ${res.status}`);
      const data=await res.json();
      render(data.items);
    }catch(error){
      console.error('[home-impact] gagal memuat data:',error);
      render([]);
    }
  }

  init();
})();
